def kth_ordered(words, k):
    if not words or k <= 0:
        return None

    # Group words by their length
    grouped_words = {}
    for word in words:
        length = len(word)
        if length not in grouped_words:
            grouped_words[length] = []
        grouped_words[length].append(word)

    # Sort each group reverse-alphabetically
    for group in grouped_words.values():
        group.sort(reverse=True)

    # Flatten the list of groups into a single sorted list by word length
    sorted_words = []
    for group in sorted(grouped_words.keys()):
        sorted_words.extend(grouped_words[group])

    # Check if k is within range and return the appropriate word
    if k > len(sorted_words):
        return None
    else:
        return sorted_words[k - 1]
